def tier_rate(plan, day):
    if day < HIGH_UNTIL:
        return {'A':0.006,'B':0.012,'C':0.030}.get(plan,0.012)
    return {'A':0.002,'B':0.006,'C':0.012}.get(plan,0.006)

def quality_recovery(day):
    # Retention/conversion adder vs the pre-action churn shock. Includes immediate tier lift and later R&D.
    if day < T8_DAY:
        return 0.035 + 0.0009*(day-DAY)
    elif day < T10_DAY:
        return 0.075
    elif day < HIGH_UNTIL:
        return 0.155
    elif day < T9_DAY:
        return 0.135
    else:
        return 0.145

def new_cash_and_cohorts(day, active_s2, active_d7, rng, scenario=0.0):
    rec=quality_recovery(day)
    paid=max(0,rng.gauss(425,85))        # raw paid S2 leads/day at $20k/d, calibrated to day267-273
    net=max(0,rng.gauss(280*(active_s2/143500)**0.45,70))
    raw_s2=paid+net
    conv=max(0.55,min(0.97,rng.gauss(0.79 + 0.55*rec + scenario*0.018,0.065)))
    active=raw_s2*conv
    a=max(0.36,min(0.58,rng.gauss(0.45,0.045)))
    cfrac=max(0.001,min(0.008,rng.lognormvariate(math.log(0.0034),0.45)))
    b=max(0,1-a-cfrac)
    nA,nB,nC=active*a,active*b,active*cfrac
    cash=nA*79+nB*159+nC*349
    mod=day%30
    new=[]
    if nA>0: new.append({'g':'S2','type':'small','plan':'A','price':79,'mod':mod,'start':day,'n':nA,'seats':nA})
    if nB>0: new.append({'g':'S2','type':'small','plan':'B','price':159,'mod':mod,'start':day,'n':nB,'seats':nB})
    if nC>0: new.append({'g':'S2','type':'small','plan':'C','price':349,'mod':mod,'start':day,'n':nC,'seats':nC})
    # D_S07 network remains hurt by support noise; ops/social/quality should repair gradually.
    d7_raw=max(0,rng.gauss(250*(active_d7/23600)**0.35,60))
    d7_conv=max(0.35,min(0.82,rng.gauss(0.58 + 0.45*rec + scenario*0.015,0.08)))
