            base={'A':0.24,'B':0.58,'C':0.92}.get(p,0.70)+scenario*0.035+0.65*rec
        else:
            base={'A':0.62,'B':0.82,'C':0.95}.get(p,0.82)+scenario*0.025+0.35*rec
    elif g=='E3':
        base=0.972+scenario*0.01+max(0,0.25*rec)
    else:
        base=0.80+scenario*0.03+0.20*rec
    # More uncertainty around first renewals while we learn if tier lift fixes the churn cliff.
    sigma=0.035+0.035*(age<75 and g in ('S2','D_S07'))
    return max(0.0,min(0.998,rng.gauss(base,sigma)))

def parse_offer_json(s):
    try:
        data=json.loads(s or '[]')
        if isinstance(data,list):
            return [(o.get('plan'),float(o.get('price_per_seat',o.get('price',0)))) for o in data if isinstance(o,dict)]
        if isinstance(data,dict):
            arr=data.get('offers') or data.get('offerings') or []
            if isinstance(arr,list):
                return [(o.get('plan'),float(o.get('price_per_seat',o.get('price',0)))) for o in arr if isinstance(o,dict)]
    except Exception: pass
    return []
current_offer_default={
 'E1':[('A',14),('B',32),('C',78)], 'E2':[('A',24),('B',56),('C',118)], 'E3':[('A',28),('B',45),('C',99)],
 'D_E02':[('A',18),('B',40),('C',92)], 'D_E07':[('A',32),('B',60),('C',126)], 'D_E08':[('A',24),('B',52),('C',112)], 'D_E09':[('A',14),('B',32),('C',78)]}

def ent_events(days,rng,scenario):
    events=[]
    mood=max(0.05,min(3.0,rng.lognormvariate(math.log(0.46+0.20*max(scenario,0)),0.9)))
    for p in pipe:
        seats=float(p['seats'] or 0)
        if seats<=0: continue
        g=p['group_id']; age=DAY-int(p['first_day'])
        if g in ('E3','D_E07','D_E08'): mu=0.0048
        elif g in ('E2','D_E02'): mu=0.0035
        else: mu=0.0025
        if age>100: mu*=0.10
        elif age>60: mu*=0.24
        elif age>30: mu*=0.45
        elif age>14: mu*=0.70
        pclose=max(0,min(0.11, rng.lognormvariate(math.log(max(mu*mood*(1+0.25*max(quality_recovery(DAY+min(days,35)),0)),1e-6)),0.9)))
        if rng.random()<pclose:
            if g in ('E1','D_E09'): delay=max(2,int(rng.gauss(10,7)))
            elif g in ('D_E02','E2'): delay=max(5,int(rng.gauss(24,14)))
            else: delay=max(7,int(rng.gauss(33,18)))
            if delay<=days:
                offers=parse_offer_json(p['offer_json']) or current_offer_default.get(g,current_offer_default['E3'])
                d={k:v for k,v in offers if k and v}
                u=rng.random()
                if g in ('E1','D_E09','D_E02') and 'A' in d and u<0.48: plan='A'
                elif 'B' in d and u<0.86: plan='B'
                elif 'C' in d: plan='C'
                elif 'B' in d: plan='B'
                else: plan='A'
                price=d.get(plan, list(d.values())[0])
                events.append({'day':DAY+delay,'g':g,'type':'large','plan':plan,'price':price,'mod':(DAY+delay)%30,'start':DAY+delay,'n':1,'seats':seats})
    return events

def ent_usage_per_seat_day(g,p):
    # usage units/seat/day (not dollars) calibrated from old enterprise active E3 B = ~83 units/d.
    if p=='A': base={'E1':18,'E2':60,'E3':45,'D_E02':35,'D_E07':58,'D_E08':40,'D_E09':25}.get(g,40)
    elif p=='B': base={'E1':35,'E2':105,'E3':83,'D_E02':70,'D_E07':110,'D_E08':78,'D_E09':45}.get(g,80)
    else: base={'E1':55,'E2':160,'E3':125,'D_E02':115,'D_E07':170,'D_E08':125,'D_E09':70}.get(g,120)
    return base

def compute_cost_per_seat_day(c,day):
    if c['type']=='large':
        units=ent_usage_per_seat_day(c['g'],c['plan'])
    else:
        units=usage_per_seat_day.get((c['g'],c['plan']), {'A':167,'B':169,'C':190}.get(c['plan'],170))
    return units*tier_rate(c['plan'],day)

def simulate(days,seed):
    rng=random.Random(seed)
    scenario=max(-1.8,min(1.8,rng.gauss(0,0.65)))
    cash=cash0
    active=[c.copy() for c in coh+ent]
    events=ent_events(days,rng,scenario)
    for day in range(DAY+1,DAY+days+1):
        rel=day-DAY
        for e in [x for x in events if x['day']==day]:
            cash += e['price']*e['seats']
            active.append(e.copy())
        active_s2=sum(c['seats'] for c in active if c['g']=='S2')
        active_d7=sum(c['seats'] for c in active if c['g']=='D_S07')
        ncash,new,leads=new_cash_and_cohorts(day,active_s2,active_d7,rng,scenario)
        cash += ncash
        active.extend(new)
        cash -= leadcost_per_day
        newactive=[]
        for c in active:
            cash -= compute_cost_per_seat_day(c,day)*c['seats']
            if day%30 == c['mod']:
                age=day-c['start']
                ret=retention(c['g'],c['plan'],age,rng,scenario,day)
                kept=c['n']*ret; kept_seats=c['seats']*ret
                if kept>0:
                    price=bill_price(c['g'],c['plan'],age,c['price'],day)
                    cash += price*kept_seats
                    cc=c.copy(); cc['n']=kept; cc['seats']=kept_seats; cc['price']=price
                    newactive.append(cc)
            else:
                newactive.append(c)
        active=newactive
        # Fixed spend. After day302 assume tier rollback and modest support/dev trim; after two months tune with scale.
        fixed = fixed_high if day < HIGH_UNTIL else fixed_low
        if rel>56:
            s2=sum(c['seats'] for c in active if c['g']=='S2')
            d7=sum(c['seats'] for c in active if c['g']=='D_S07')
            entseats=sum(c['seats'] for c in active if c['type']=='large')
            ops = 5000 + 235000*(max(s2,1)/143500)**0.52 + 45000*(max(d7,1)/23600)**0.60 + 9600
            dev = 5000 + 26000*(max(s2,1)/143500)**0.35 + 3500*(max(d7,1)/23600)**0.35 + 8500
            ads = 20000
            cap = 75000 if entseats>250000 or sum(c['seats'] for c in active)>270000 else 28000
            entops = min(90000, 0.12*max(0,entseats-50000))
            fixed = max(300000,min(570000,ops+dev+ads+cap+entops))
        cash -= fixed
    return cash

for days in [7,28,84,182]:
    nseeds = 360 if days<=28 else (240 if days<=84 else 170)
    vals=[]
    for i in range(nseeds):
        vals.append(simulate(days,39000+i))
    vals.sort(); point=statistics.median(vals); mean=statistics.mean(vals)
    def pct(p): return vals[max(0,min(len(vals)-1,int(p*len(vals))))]
    print('H',days,'mean',round(mean),'median',round(point),'p2.5',round(pct(.025)),'p10',round(pct(.1)),'p90',round(pct(.9)),'p97.5',round(pct(.975)),'min',round(vals[0]),'max',round(vals[-1]))
